#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* L = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &L[i]);
        }
        int count = 0;
        int* stack = (int*) malloc(n * sizeof(int));
        int top = -1;
        for (int i = 0; i < n; i++) {
            while (top >= 0 && stack[top] > L[i]) {
                top--;
                count++;
            }
            stack[++top] = L[i];
        }
        count += top + 1;
        printf("%d\n", count);
        free(L);
        free(stack);
    }
    return 0;
}

