#include <iostream>
#include <stack>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        int* L = new int[n];
        for (int i = 0; i < n; i++) {
            cin >> L[i];
        }
        int count = 0;
        stack<int> s;
        for (int i = 0; i < n; i++) {
            while (!s.empty() && s.top() > L[i]) {
                s.pop();
                count++;
            }
            s.push(L[i]);
        }
        count += s.size();
        cout << count << endl;
        delete[] L;
    }
    return 0;
}

