// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
import java.util.Stack;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] L = new int[n];
            for (int i = 0; i < n; i++) {
                L[i] = sc.nextInt();
            }
            int count = 0;
            Stack<Integer> stack = new Stack<>();
            for (int i = 0; i < n; i++) {
                while (!stack.isEmpty() && stack.peek() > L[i]) {
                    stack.pop();
                    count++;
                }
                stack.push(L[i]);
            }
            count += stack.size();
            System.out.println(count);
        }
    }
}

