let idx = 0;

function readline() {
    return lines[idx++];
}

let T = parseInt(readline());
while (T-- > 0) {
    let n = parseInt(readline());
    let L = readline().split(' ').map(x => parseInt(x));
    let count = 0;
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length > 0 && stack[stack.length - 1] > L[i]) {
            stack.pop();
            count++;
        }
        stack.push(L[i]);
    }
    count += stack.length;
    console.log(count);
}

